     1→import type { SearchField, SearchFieldUnit, SearchInstitution, SearchOutputField, Theme } from './types'
     2→
     3→// Field names rendered first in the sidebar, in order. Unknown fields follow alphabetically by label.
     4→export const PREFERRED_ORDER = ['name', 'city', 'state']
     5→
     6→export function sortFields(fields: SearchField[]): SearchField[] {
     7→  return [...fields].sort((a, b) => {
     8→    const ai = PREFERRED_ORDER.indexOf(a.name)
     9→    const bi = PREFERRED_ORDER.indexOf(b.name)
    10→    if (ai !== -1 && bi !== -1) return ai - bi
    11→    if (ai !== -1) return -1
    12→    if (bi !== -1) return 1
    13→    return a.label.localeCompare(b.label)
    14→  })
    15→}
    16→
    17→// Ordered list of themes for sidebar rendering. Only themes with fields are shown.
    18→export const THEME_ORDER: Theme[] = [
    19→  'CORE',
    20→  'LOCATION',
    21→  'ACADEMICS',
    22→  'COST',
    23→  'OUTCOMES',
    24→  'RANKING',
    25→  'ADMISSIONS',
    26→  'ATHLETICS',
    27→  'FIELDS_OF_STUDY',
    28→  'CULTURAL_ENVIRONMENT',
    29→  'WEATHER',
    30→]
    31→
    32→export const THEME_LABELS: Record<Theme, string> = {
    33→  CORE: 'Core',
    34→  LOCATION: 'Location',
    35→  ACADEMICS: 'Academics',
    36→  COST: 'Cost & Financial Aid',
    37→  OUTCOMES: 'Outcomes',
    38→  RANKING: 'Rankings',
    39→  ADMISSIONS: 'Admissions',
    40→  ATHLETICS: 'Athletics',
    41→  FIELDS_OF_STUDY: 'Fields of Study',
    42→  CULTURAL_ENVIRONMENT: 'Cultural Environment',
    43→  WEATHER: 'Weather & Climate',
    44→  PHYSICAL_ENVIRONMENT: 'Physical Environment',
    45→  DEMOGRAPHICS: 'Demographics',
    46→  REPUTATION: 'Reputation',
    47→  SAFETY: 'Safety',
    48→  STUDENT_LIFE: 'Student Life',
    49→  METADATA: 'Metadata',
    50→  OTHER: 'Other',
    51→}
    52→
    53→export interface ThemeGroup {
    54→  theme: Theme
    55→  label: string
    56→  fields: SearchField[]
    57→}
    58→
    59→export function fieldsByTheme(fields: SearchField[]): ThemeGroup[] {
    60→  // Group fields by theme
    61→  const grouped = new Map<Theme, SearchField[]>()
    62→  for (const f of fields) {
    63→    const existing = grouped.get(f.theme)
    64→    if (existing) {
    65→      existing.push(f)
    66→    } else {
    67→      grouped.set(f.theme, [f])
    68→    }
    69→  }
    70→
    71→  // Sort fields within each group alphabetically by label
    72→  for (const group of grouped.values()) {
    73→    group.sort((a, b) => a.label.localeCompare(b.label))
    74→  }
    75→
    76→  // Build ordered result: known themes first, then any unknown themes
    77→  const result: ThemeGroup[] = []
    78→  for (const theme of THEME_ORDER) {
    79→    const group = grouped.get(theme)
    80→    if (group && group.length > 0) {
    81→      result.push({ theme, label: THEME_LABELS[theme], fields: group })
    82→      grouped.delete(theme)
    83→    }
    84→  }
    85→  // Append any remaining themes not in THEME_ORDER
    86→  for (const [theme, group] of grouped) {
    87→    if (group.length > 0) {
    88→      result.push({ theme, label: THEME_LABELS[theme] ?? String(theme), fields: group })
    89→    }
    90→  }
    91→
    92→  return result
    93→}
