    95→const MILES_TO_KM = 1.60934
    96→
    97→export function buildFilterInputs(
    98→  filters: Record<string, unknown>,
    99→): Array<{ field: string; value: unknown }> {
   100→  return Object.entries(filters).map(([field, value]) => {
   101→    if (
   102→      typeof value === 'object' &&
   103→      value !== null &&
   104→      'latitude' in value &&
   105→      'longitude' in value &&
   106→      'radiusMiles' in value
   107→    ) {
   108→      const v = value as { latitude: number; longitude: number; radiusMiles: number }
   109→      return {
   110→        field,
   111→        value: {
   112→          kind: 'radius',
   113→          radius: { lat: v.latitude, lng: v.longitude, radius_km: v.radiusMiles * MILES_TO_KM },
   114→        },
   115→      }
   116→    }
   117→    return { field, value }
   118→  })
   119→}
   120→
   121→export function serializeFilterValue(value: unknown): string {
   122→  if (typeof value === 'object' && value !== null) {
   123→    if ('query' in value) return String((value as { query: string }).query)
   124→    if ('value' in value) return String((value as { value: string }).value)
   125→    if ('values' in value) return (value as { values: string[] }).values.join(',')
   126→    if ('latitude' in value && 'longitude' in value && 'radiusMiles' in value) {
   127→      const g = value as { latitude: number; longitude: number; radiusMiles: number }
   128→      return `${g.latitude},${g.longitude},${g.radiusMiles}`
   129→    }
   130→    if ('max' in value && !('min' in value))
   131→      return String((value as { max: number }).max)
   132→    if ('min' in value && !('max' in value))
   133→      return String((value as { min: number }).min)
   134→    if ('min' in value && 'max' in value) {
   135→      const r = value as { min: number; max: number }
   136→      return `${r.min},${r.max}`
   137→    }
   138→  }
   139→  return String(value)
   140→}
   141→
   142→export function parseUrlToFilters(
   143→  params: URLSearchParams,
   144→  fields: SearchField[],
   145→): Record<string, unknown> {
   146→  const filters: Record<string, unknown> = {}
   147→  const fieldMap = new Map(fields.map((f) => [f.name, f]))
   148→
   149→  // Handle legacy ?q= param — maps to the "name" field
   150→  const q = params.get('q')
   151→  if (q && !params.has('name')) {
   152→    filters.name = { query: q }
   153→  }
   154→
   155→  for (const [key, raw] of params.entries()) {
   156→    if (key === 'q') continue
   157→    const field = fieldMap.get(key)
   158→    if (!field) continue
   159→
   160→    if (field.__typename === 'TextSearchField') {
   161→      filters[key] = { query: raw }
   162→    } else if (field.__typename === 'BinarySearchField') {
   163→      filters[key] = { value: raw }
   164→    } else if (field.__typename === 'ChoiceSearchField') {
   165→      if (field.maxSelections === 1) {
   166→        filters[key] = { value: raw }
   167→      } else {
   168→        filters[key] = { values: raw.split(',').filter(Boolean) }
   169→      }
