import { Box, Table, UnstyledButton, Group, Text } from '@mantine/core'
import { ArrowUp, ArrowDown, ArrowUpDown } from 'lucide-react'
import type { SearchInstitution, SearchOutputField } from './types'
import { formatCellValue, getFieldValue } from './helpers'
import { DataSourceTooltip } from './DataSourceTooltip'
import type { DataSource } from './useDataSources'

export interface SortState {
  field: string
  direction: 'ASC' | 'DESC'
}

interface ResultsTableProps {
  institutions: SearchInstitution[]
  outputFields: SearchOutputField[]
  visibleColumns: Set<string>
  columnOrder: string[]
  onClickInstitution: (unitID: string) => void
  hasLocation: boolean
  hasState: boolean
  hasBlend?: boolean
  sort?: SortState
  onSort?: (field: string) => void
  dataSources?: Map<string, DataSource>
}

function formatDistance(distance: number | null | undefined): string {
  if (distance === null || distance === undefined) return '—'
  if (distance < 1) return '< 1 mi'
  return `${Math.round(distance).toLocaleString()} mi`
}

function formatMyPrice(price: number | null | undefined): string {
  if (price === null || price === undefined) return '—'
  return `$${Math.round(price).toLocaleString()}`
}

function SortIcon({ field, sort }: { field: string; sort?: SortState }) {
  if (sort?.field !== field) return <ArrowUpDown size={14} opacity={0.3} />
  if (sort.direction === 'ASC') return <ArrowUp size={14} />
  return <ArrowDown size={14} />
}

function SortableHeader({
  label,
  field,
  sort,
  onSort,
  style,
  source,
}: {
  label: string
  field: string
  sort?: SortState
  onSort?: (field: string) => void
  style?: React.CSSProperties
  source?: DataSource
}) {
  if (!onSort) {
    return (
      <Table.Th style={style}>
        <Group gap={4} wrap="nowrap">
          {label}
          <DataSourceTooltip source={source} />
        </Group>
      </Table.Th>
    )
  }
  return (
    <Table.Th style={{ ...style, cursor: 'pointer', userSelect: 'none' }}>
      <UnstyledButton onClick={() => onSort(field)} data-testid={`sort-${field}`}>
        <Group gap={4} wrap="nowrap">
          <Text size="sm" fw={600} component="span">
            {label}
          </Text>
          <SortIcon field={field} sort={sort} />
          <DataSourceTooltip source={source} />
        </Group>
      </UnstyledButton>
    </Table.Th>
  )
}

function formatBlendScore(score: number | null | undefined): string {
  if (score === null || score === undefined) return '—'
  return (score * 100).toFixed(1)
}

export function ResultsTable({
  institutions,
  outputFields,
  visibleColumns,
  columnOrder,
  onClickInstitution,
  hasLocation,
  hasState,
  hasBlend,
  sort,
  onSort,
  dataSources,
}: ResultsTableProps) {
  // Build a lookup of output fields by name
  const fieldsByName = new Map(outputFields.map((f) => [f.name, f]))

  // Special columns have custom rendering and conditional visibility
  const specialRenderers = new Set(['city', 'state', 'distance', 'myPrice'])

  // Determine visibility of special conditional columns
  const showDistance = hasLocation
  const showMyPrice = hasState

  // Check if a column should be visible
  function isColumnVisible(name: string): boolean {
    if (name === 'name') return false // pinned, handled separately
    if (name === 'distance') return showDistance
    if (name === 'myPrice') return showMyPrice
    if (specialRenderers.has(name)) return visibleColumns.has(name)
    return visibleColumns.has(name) && fieldsByName.has(name)
  }

  // Use columnOrder to determine column sequence (excluding pinned "name")
  const orderedColumns = columnOrder.filter(isColumnVisible)

  // Extra fields are ordered columns that aren't special-rendered
  const orderedExtraFields = orderedColumns
    .filter((name) => !specialRenderers.has(name))
    .map((name) => fieldsByName.get(name)!)

  // Group consecutive extra fields by theme for the spanning header row
  const themeGroups: { theme: string; label: string; fields: SearchOutputField[] }[] = []
  for (const field of orderedExtraFields) {
    const last = themeGroups[themeGroups.length - 1]
    if (last && last.theme === field.theme) {
      last.fields.push(field)
    } else {
      const label =
        { CORE: 'Core', LOCATION: 'Location', ACADEMICS: 'Academics', COST: 'Cost & Financial Aid', OUTCOMES: 'Outcomes', RANKING: 'Rankings', ADMISSIONS: 'Admissions', ATHLETICS: 'Athletics', FIELDS_OF_STUDY: 'Fields of Study', CULTURAL_ENVIRONMENT: 'Cultural Environment', WEATHER: 'Weather & Climate', PHYSICAL_ENVIRONMENT: 'Physical Environment', DEMOGRAPHICS: 'Demographics', REPUTATION: 'Reputation', SAFETY: 'Safety', STUDENT_LIFE: 'Student Life', METADATA: 'Metadata', OTHER: 'Other' }[field.theme] ?? field.theme
      themeGroups.push({ theme: field.theme, label, fields: [field] })
    }
  }

  // Special columns in their user-defined order
  const specialColumnOrder = orderedColumns.filter((n) => specialRenderers.has(n))

  // Number of fixed columns before extra fields: name + visible special columns + blend
  const fixedColCount = 1 + specialColumnOrder.length + (hasBlend ? 1 : 0)

  const stickyStyle = {
    position: 'sticky' as const,
    left: 0,
    background: 'var(--mantine-color-body)',
    zIndex: 1,
  }

  function renderSpecialHeader(name: string) {
    switch (name) {
      case 'city':
        return <SortableHeader key="city" label="City" field="city" sort={sort} onSort={onSort} />
      case 'state':
        return <Table.Th key="state">State</Table.Th>
      case 'distance':
        return <SortableHeader key="distance" label="Distance" field="distance" sort={sort} onSort={onSort} />
      case 'myPrice':
        return <Table.Th key="myPrice">My Price</Table.Th>
      default:
        return null
    }
  }

  function renderSpecialCell(name: string, inst: SearchInstitution) {
    switch (name) {
      case 'city':
        return <Table.Td key="city">{inst.city}</Table.Td>
      case 'state':
        return <Table.Td key="state">{inst.state}</Table.Td>
      case 'distance':
        return <Table.Td key="distance" data-testid="distance">{formatDistance(inst.distance)}</Table.Td>
      case 'myPrice':
        return <Table.Td key="myPrice" data-testid="my-price">{formatMyPrice(inst.myPrice)}</Table.Td>
      default:
        return null
    }
  }

  return (
    <Box style={{ overflowX: 'auto' }}>
      <Table striped highlightOnHover>
        <Table.Thead>
          {themeGroups.length > 0 && (
            <Table.Tr>
              <Table.Th colSpan={fixedColCount} style={{ border: 'none' }} />
              {themeGroups.map((group, i) => (
                <Table.Th
                  key={`${group.theme}-${i}`}
                  colSpan={group.fields.length}
                  data-testid={`theme-group-${group.theme}`}
                  style={{
                    textAlign: 'center',
                    borderBottom: 'none',
                    paddingBottom: 0,
                  }}
                >
                  <Text fz="xs" fw={600} c="dimmed" tt="uppercase">
                    {group.label}
                  </Text>
                </Table.Th>
              ))}
            </Table.Tr>
          )}
          <Table.Tr>
            <SortableHeader
              label="Name"
              field="name"
              sort={sort}
              onSort={onSort}
              style={stickyStyle}
            />
            {specialColumnOrder.map((name) => renderSpecialHeader(name))}
            {hasBlend && <Table.Th>Blend Score</Table.Th>}
            {orderedExtraFields.map((field) => {
              const source = field.dataSourceID
                ? dataSources?.get(field.dataSourceID)
                : undefined
              return field.sortable ? (
                <SortableHeader
                  key={field.name}
                  label={field.label}
                  field={field.name}
                  sort={sort}
                  onSort={onSort}
                  source={source}
                />
              ) : (
                <Table.Th key={field.name}>
                  <Group gap={4} wrap="nowrap">
                    {field.label}
                    <DataSourceTooltip source={source} />
                  </Group>
                </Table.Th>
              )
            })}
          </Table.Tr>
        </Table.Thead>
        <Table.Tbody>
          {institutions.map((inst) => (
            <Table.Tr
              key={inst.unitID}
              onClick={() => onClickInstitution(inst.unitID)}
              style={{ cursor: 'pointer' }}
            >
              <Table.Td
                fw={600}
                c="brand.9"
                style={{
                  position: 'sticky',
                  left: 0,
                  background: 'inherit',
                  zIndex: 1,
                }}
              >
                {inst.name}
              </Table.Td>
              {specialColumnOrder.map((name) => renderSpecialCell(name, inst))}
              {hasBlend && (
                <Table.Td data-testid="blend-score">{formatBlendScore(inst.blendScore)}</Table.Td>
              )}
              {orderedExtraFields.map((field) => (
                <Table.Td key={field.name}>
                  {formatCellValue(getFieldValue(inst, field.outputKey), field.unit)}
                </Table.Td>
              ))}
            </Table.Tr>
          ))}
        </Table.Tbody>
      </Table>
    </Box>
  )
}

import { jsPDF } from 'jspdf'
import autoTable from 'jspdf-autotable'
import type { DataSource } from './useDataSources'
import type { SearchInstitution, SearchOutputField } from './types'
import { formatCellValue, getFieldValue } from './helpers'

// Direct fields live on SearchInstitution as top-level properties
const DIRECT_FIELDS: Record<string, (inst: SearchInstitution) => string> = {
  name: (inst) => inst.name,
  city: (inst) => inst.city,
  state: (inst) => inst.state,
}

function getCellValue(inst: SearchInstitution, field: SearchOutputField): string {
  const directFn = DIRECT_FIELDS[field.name]
  if (directFn) return directFn(inst)
  const raw = getFieldValue(inst, field.outputKey)
  return formatCellValue(raw, field.unit)
}

export interface PdfExportOptions {
  institutions: SearchInstitution[]
  outputFields: SearchOutputField[]
  activeFilters?: string[]
  maxRows: number
  dataSources?: Map<string, DataSource>
}

export function generateSearchPdf(options: PdfExportOptions): jsPDF {
  const { institutions, outputFields, activeFilters, maxRows, dataSources } = options

  const exportableFields = outputFields.filter((f) => f.exportable)
  const rows = institutions.slice(0, maxRows)

  const doc = new jsPDF({ orientation: 'landscape', unit: 'pt', format: 'letter' })
  const pageWidth = doc.internal.pageSize.getWidth()

  // Title
  doc.setFontSize(16)
  doc.setTextColor(14, 31, 64) // --color-primary #0e1f40
  doc.text('College Power Search — Export', 40, 40)

  // Timestamp
  doc.setFontSize(9)
  doc.setTextColor(100, 116, 139) // slate-500
  doc.text(`Generated ${new Date().toLocaleString()}`, 40, 56)

  // Active filters summary
  let startY = 70
  if (activeFilters && activeFilters.length > 0) {
    doc.setFontSize(9)
    doc.setTextColor(71, 85, 105) // slate-600
    const filterText = `Filters: ${activeFilters.join(', ')}`
    const lines = doc.splitTextToSize(filterText, pageWidth - 80)
    doc.text(lines, 40, startY)
    startY += lines.length * 12 + 8
  }

  // Results table
  const headers = exportableFields.map((f) => f.label)
  const body = rows.map((inst) => exportableFields.map((f) => getCellValue(inst, f)))

  autoTable(doc, {
    head: [headers],
    body,
    startY,
    margin: { left: 40, right: 40 },
    styles: { fontSize: 8, cellPadding: 4 },
    headStyles: {
      fillColor: [14, 31, 64], // --color-primary
      textColor: [255, 255, 255],
      fontStyle: 'bold',
    },
    alternateRowStyles: { fillColor: [241, 245, 249] }, // slate-100
  })

  // Data sources citation section
  if (dataSources && dataSources.size > 0) {
    const seen = new Set<string>()
    const usedSources: DataSource[] = []
    for (const f of exportableFields) {
      const id = f.dataSourceID
      if (id && !seen.has(id)) {
        seen.add(id)
        const ds = dataSources.get(id)
        if (ds) usedSources.push(ds)
      }
    }
    if (usedSources.length > 0) {
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const lastTableY = (doc as any).lastAutoTable?.finalY ?? doc.internal.pageSize.getHeight() - 80
      autoTable(doc, {
        head: [['Data Sources', '', '']],
        body: usedSources.map((ds) => [ds.name, ds.dataset, ds.url]),
        startY: lastTableY + 16,
        margin: { left: 40, right: 40 },
        styles: { fontSize: 7, cellPadding: 3 },
        headStyles: {
          fillColor: [71, 85, 105], // slate-600
          textColor: [255, 255, 255],
          fontStyle: 'bold',
        },
        columnStyles: {
          0: { cellWidth: 200 },
        },
      })
    }
  }

  // Page count footer on every page
  const pageCount = doc.getNumberOfPages()
  for (let i = 1; i <= pageCount; i++) {
    doc.setPage(i)
    const pageHeight = doc.internal.pageSize.getHeight()
    doc.setFontSize(8)
    doc.setTextColor(148, 163, 184) // slate-400
    doc.text(`Page ${i} of ${pageCount}`, pageWidth / 2, pageHeight - 20, { align: 'center' })
    if (institutions.length >= maxRows) {
      doc.text(
        `Results limited to ${maxRows} rows`,
        pageWidth - 40,
        pageHeight - 20,
        { align: 'right' },
      )
    }
  }

  return doc
}

export function downloadSearchPdf(options: PdfExportOptions): void {
  const doc = generateSearchPdf(options)
  doc.save('college-power-search-export.pdf')
}

import { useState } from 'react'
import {
  Anchor,
  Badge,
  Divider,
  Group,
  Modal,
  SimpleGrid,
  Stack,
  Text,
} from '@mantine/core'
import { Button } from '@/components/ui/button'
import { useMediaQuery } from '@mantine/hooks'
import type { SearchInstitution } from './types'
import { SimilarInstitutions } from './SimilarInstitutions'

// ── Code-to-label mappings ──────────────────────────────────────────────────

const INSTITUTION_TYPES: Record<string, string> = {
  '1': 'Public',
  '2': 'Private nonprofit',
  '3': 'Private for-profit',
}

const HIGHEST_DEGREES: Record<string, string> = {
  '1': 'Certificate',
  '2': "Associate's",
  '3': "Bachelor's",
  '4': "Master's",
  '5': 'Doctorate',
}

const LOCALE_LABELS: Record<string, string> = {
  '11': 'City: Large',
  '12': 'City: Midsize',
  '13': 'City: Small',
  '21': 'Suburb: Large',
  '22': 'Suburb: Midsize',
  '23': 'Suburb: Small',
  '31': 'Town: Fringe',
  '32': 'Town: Distant',
  '33': 'Town: Remote',
  '41': 'Rural: Fringe',
  '42': 'Rural: Distant',
  '43': 'Rural: Remote',
}

const REGION_LABELS: Record<string, string> = {
  '0': 'U.S. Service Schools',
  '1': 'New England',
  '2': 'Mid East',
  '3': 'Great Lakes',
  '4': 'Plains',
  '5': 'Southeast',
  '6': 'Southwest',
  '7': 'Rocky Mountains',
  '8': 'Far West',
  '9': 'Outlying Areas',
}

const NCAA_DIVISIONS: Record<string, string> = {
  '1': 'Division I',
  '2': 'Division II',
  '3': 'Division III',
}

const KOPPEN_CLIMATE: Record<string, string> = {
  A: 'Tropical',
  B: 'Dry',
  C: 'Temperate',
  D: 'Continental',
  E: 'Polar',
}

const PARTISAN_LABELS: Record<string, string> = {
  D: 'Democrat',
  R: 'Republican',
}

// ── Formatters ──────────────────────────────────────────────────────────────

function formatPercent(value: number | null | undefined): string {
  if (value == null) return '—'
  return `${(value * 100).toFixed(1)}%`
}

function formatCurrency(value: number | null | undefined): string {
  if (value == null) return '—'
  return `$${value.toLocaleString()}`
}

function formatNumber(value: number | null | undefined): string {
  if (value == null) return '—'
  return value.toLocaleString()
}

function mapLabel(
  value: string | null | undefined,
  labels: Record<string, string>,
): string {
  if (value == null) return '—'
  return labels[value] ?? value
}

function formatRange(low: number | null | undefined, high: number | null | undefined): string {
  if (low == null && high == null) return '—'
  if (low != null && high != null) return `${low.toLocaleString()}–${high.toLocaleString()}`
  if (low != null) return `${low.toLocaleString()}+`
  return `≤${high!.toLocaleString()}`
}

// ── Sub-components ──────────────────────────────────────────────────────────

function DetailRow({ label, value }: { label: string; value: string }) {
  if (value === '—') return null
  return (
    <Group
      justify="space-between"
      style={{ borderBottom: '1px solid var(--mantine-color-gray-2)' }}
      py="xs"
    >
      <Text size="sm" c="dimmed">
        {label}
      </Text>
      <Text size="sm" fw={500}>
        {value}
      </Text>
    </Group>
  )
}

function LinkRow({ label, url }: { label: string; url: string | null | undefined }) {
  if (!url) return null
  const href = url.startsWith('http') ? url : `https://${url}`
  return (
    <Group
      justify="space-between"
      style={{ borderBottom: '1px solid var(--mantine-color-gray-2)' }}
      py="xs"
    >
      <Text size="sm" c="dimmed">
        {label}
      </Text>
      <Anchor href={href} target="_blank" rel="noopener noreferrer" size="sm" fw={500}>
        {url}
      </Anchor>
    </Group>
  )
}

function SectionHeader({ children }: { children: string }) {
  return (
    <Text size="xs" fw={700} tt="uppercase" c="dimmed" mb="xs">
      {children}
    </Text>
  )
}

// ── Props ───────────────────────────────────────────────────────────────────

interface InstitutionDetailProps {
  institution: SearchInstitution | null
  opened: boolean
  onClose: () => void
}

// ── Component ───────────────────────────────────────────────────────────────

export function InstitutionDetail({ institution: inst, opened, onClose }: InstitutionDetailProps) {
  const isMobile = useMediaQuery('(max-width: 48em)')
  const [showSimilar, setShowSimilar] = useState(false)

  return (
    <Modal
      opened={opened}
      onClose={onClose}
      fullScreen={isMobile ?? false}
      size="xl"
      title={inst?.name ?? 'Institution Details'}
      aria-label="Institution details"
    >
      {!inst && (
        <Text c="dimmed" size="sm">
          Institution not found.
        </Text>
      )}
      {inst && (
        <Stack gap="md">
          {/* Header */}
          <div>
            <Text size="lg" fw={700} c="brand.9">
              {inst.name}
            </Text>
            <Text size="sm" c="dimmed">
              {inst.city}, {inst.state}
            </Text>
          </div>

          <SimpleGrid cols={{ base: 1, sm: 2 }} spacing="lg">
            {/* Core / Academics */}
            <Stack gap={0}>
              <SectionHeader>Core</SectionHeader>
              <DetailRow
                label="Type"
                value={mapLabel(inst.academics?.institutionType, INSTITUTION_TYPES)}
              />
              <DetailRow
                label="Highest Degree"
                value={mapLabel(inst.academics?.highestDegree, HIGHEST_DEGREES)}
              />
              <DetailRow
                label="Student-Faculty Ratio"
                value={
                  inst.academics?.studentFacultyRatio != null
                    ? `${inst.academics.studentFacultyRatio}:1`
                    : '—'
                }
              />
              <DetailRow
                label="Full-Time Faculty"
                value={formatPercent(inst.academics?.fullTimeFacultyRate)}
              />
              <DetailRow
                label="Gender"
                value={
                  inst.academics?.gender === 'coed'
                    ? 'Coeducational'
                    : inst.academics?.gender === 'men-only'
                      ? 'Men Only'
                      : inst.academics?.gender === 'women-only'
                        ? 'Women Only'
                        : '—'
                }
              />
            </Stack>

            {/* Location */}
            <Stack gap={0}>
              <SectionHeader>Location</SectionHeader>
              <DetailRow label="City" value={inst.city} />
              <DetailRow label="State" value={inst.state} />
              <DetailRow
                label="Setting"
                value={mapLabel(inst.locationDetails?.locale, LOCALE_LABELS)}
              />
              <DetailRow
                label="Region"
                value={mapLabel(inst.locationDetails?.region, REGION_LABELS)}
              />
              {inst.locationDetails?.metroArea && (
                <DetailRow label="Metro Area" value={inst.locationDetails.metroArea} />
              )}
            </Stack>

            {/* Cost */}
            <Stack gap={0}>
              <SectionHeader>Cost</SectionHeader>
              <DetailRow
                label="In-State Tuition"
                value={formatCurrency(inst.cost?.tuitionInState)}
              />
              <DetailRow
                label="Out-of-State Tuition"
                value={formatCurrency(inst.cost?.tuitionOutOfState)}
              />
              <DetailRow label="Net Price" value={formatCurrency(inst.cost?.avgNetPrice)} />
              <DetailRow label="Room & Board" value={formatCurrency(inst.cost?.roomAndBoard)} />
            </Stack>

            {/* Admissions */}
            <Stack gap={0}>
              <SectionHeader>Admissions</SectionHeader>
              <DetailRow
                label="Acceptance Rate"
                value={formatPercent(inst.outcomes?.admissionRate)}
              />
              <DetailRow
                label="SAT Math"
                value={formatRange(inst.admissions?.satMath25, inst.admissions?.satMath75)}
              />
              <DetailRow
                label="SAT Verbal"
                value={formatRange(inst.admissions?.satVerbal25, inst.admissions?.satVerbal75)}
              />
              <DetailRow
                label="ACT Composite"
                value={formatRange(
                  inst.admissions?.actComposite25,
                  inst.admissions?.actComposite75,
                )}
              />
              {inst.admissions?.applicationPlatforms &&
                inst.admissions.applicationPlatforms.length > 0 && (
                  <DetailRow
                    label="Apply Via"
                    value={inst.admissions.applicationPlatforms.join(', ')}
                  />
                )}
            </Stack>

            {/* Outcomes */}
            <Stack gap={0}>
              <SectionHeader>Outcomes</SectionHeader>
              <DetailRow
                label="Graduation Rate"
                value={formatPercent(inst.outcomes?.graduationRate)}
              />
              <DetailRow
                label="Retention Rate"
                value={formatPercent(inst.outcomes?.retentionRate)}
              />
              <DetailRow
                label="Transfer Rate"
                value={formatPercent(inst.outcomes?.transferRate)}
              />
            </Stack>

            {/* Rankings */}
            {inst.rankings && (
              <Stack gap={0}>
                <SectionHeader>Rankings</SectionHeader>
                <DetailRow
                  label="US News National"
                  value={formatNumber(inst.rankings.usNewsNational)}
                />
                <DetailRow
                  label="US News Liberal Arts"
                  value={formatNumber(inst.rankings.usNewsLiberalArts)}
                />
                <DetailRow label="Forbes" value={formatNumber(inst.rankings.forbes)} />
                <DetailRow
                  label="Wash. Monthly National"
                  value={formatNumber(inst.rankings.washingtonMonthlyNational)}
                />
                <DetailRow
                  label="Wash. Monthly Liberal Arts"
                  value={formatNumber(inst.rankings.washingtonMonthlyLiberalArts)}
                />
                <DetailRow label="Niche" value={formatNumber(inst.rankings.niche)} />
                <DetailRow
                  label="Money Score"
                  value={
                    inst.rankings.moneyScore != null
                      ? inst.rankings.moneyScore.toFixed(1)
                      : '—'
                  }
                />
                {inst.blendScore != null && (
                  <DetailRow label="Blend Score" value={inst.blendScore.toFixed(1)} />
                )}
              </Stack>
            )}

            {/* Athletics */}
            {inst.athletics && (
              <Stack gap={0}>
                <SectionHeader>Athletics</SectionHeader>
                <DetailRow
                  label="NCAA Division"
                  value={mapLabel(inst.athletics.ncaaDivision, NCAA_DIVISIONS)}
                />
                {inst.athletics.ncaaConference && (
                  <DetailRow label="Conference" value={inst.athletics.ncaaConference} />
                )}
              </Stack>
            )}

            {/* Demographics */}
            {inst.demographics && (
              <Stack gap={0}>
                <SectionHeader>Demographics</SectionHeader>
                <DetailRow
                  label="Total Enrollment"
                  value={formatNumber(inst.demographics.totalEnrollment)}
                />
                {inst.academics?.gradEnrollment != null && (
                  <DetailRow
                    label="Graduate Enrollment"
                    value={formatNumber(inst.academics.gradEnrollment)}
                  />
                )}
                <DetailRow label="Male" value={formatPercent(inst.demographics.percentMale)} />
                <DetailRow
                  label="Female"
                  value={formatPercent(inst.demographics.percentFemale)}
                />
                {(inst.demographics.hbcu ||
                  inst.demographics.hsi ||
                  inst.demographics.aanapisi ||
                  inst.demographics.pbi) && (
                  <Group gap="xs" mt="xs">
                    {inst.demographics.hbcu && (
                      <Badge size="sm" variant="light" color="brand">
                        HBCU
                      </Badge>
                    )}
                    {inst.demographics.hsi && (
                      <Badge size="sm" variant="light" color="brand">
                        HSI
                      </Badge>
                    )}
                    {inst.demographics.aanapisi && (
                      <Badge size="sm" variant="light" color="brand">
                        AANAPISI
                      </Badge>
                    )}
                    {inst.demographics.pbi && (
                      <Badge size="sm" variant="light" color="brand">
                        PBI
                      </Badge>
                    )}
                  </Group>
                )}
              </Stack>
            )}

            {/* Cultural Environment */}
            {inst.culture && (
              <Stack gap={0}>
                <SectionHeader>Cultural Environment</SectionHeader>
                <DetailRow
                  label="Partisan Lean"
                  value={
                    inst.culture.partisanDirection && inst.culture.partisanScore != null
                      ? `${mapLabel(inst.culture.partisanDirection, PARTISAN_LABELS)} +${inst.culture.partisanScore.toFixed(1)}`
                      : '—'
                  }
                />
                {inst.culture.religiousAffiliation && (
                  <DetailRow
                    label="Religious Affiliation"
                    value={inst.culture.religiousAffiliation}
                  />
                )}
              </Stack>
            )}

            {/* Weather */}
            {inst.climate && (
              <Stack gap={0}>
                <SectionHeader>Weather</SectionHeader>
                <DetailRow
                  label="Climate"
                  value={mapLabel(inst.climate.koppenClimate, KOPPEN_CLIMATE)}
                />
                <DetailRow
                  label="Temperature"
                  value={inst.climate.koppenTemperature ?? '—'}
                />
                <DetailRow
                  label="Precipitation"
                  value={inst.climate.koppenPrecipitation ?? '—'}
                />
              </Stack>
            )}

            {/* Metadata */}
            {inst.meta && (
              <Stack gap={0}>
                <SectionHeader>Metadata</SectionHeader>
                <LinkRow label="Website" url={inst.meta.schoolUrl} />
                {inst.meta.accreditor && (
                  <DetailRow label="Accreditor" value={inst.meta.accreditor} />
                )}
              </Stack>
            )}
          </SimpleGrid>

          <Divider />

          {!showSimilar ? (
            <Button variant="light" size="sm" onClick={() => setShowSimilar(true)}>
              Find Similar Schools
            </Button>
          ) : (
            <Stack gap="sm">
              <Text size="xs" fw={700} tt="uppercase" c="dimmed">
                Similar Schools
              </Text>
              <SimilarInstitutions unitID={inst.unitID} />
            </Stack>
          )}
        </Stack>
      )}
    </Modal>
  )
}

